import{_ as a,o as r,c as e,ag as i}from"./chunks/framework.WmBmIPw-.js";const c=JSON.parse('{"title":"启发式算法","description":"","frontmatter":{},"headers":[],"relativePath":"or-opt/heuristic-algorithms.md","filePath":"or-opt/heuristic-algorithms.md","lastUpdated":1777186229000}'),s={name:"or-opt/heuristic-algorithms.md"};function l(h,t,o,m,n,d){return r(),e("div",null,[...t[0]||(t[0]=[i('<h1 id="启发式算法" tabindex="-1">启发式算法 <a class="header-anchor" href="#启发式算法" aria-label="Permalink to &quot;启发式算法&quot;">​</a></h1><p>与<a href="./exact-algorithms.html">精确算法</a>相对：启发式在可接受计算代价下求好的可行解或可行界，不保证在有限步内对任意实例证明全局最优（除非在特定结构下可证——那时往往已可纳入精确或近似理论框架讨论）。</p><p>在文献与工程实践中，常把基于启发式思想的方法按抽象层次区分为以下三类。本库后续会按子页 <a href="./simple-heuristics.html">基础启发式</a>、<a href="./metaheuristics.html">元启发式</a>、<a href="./hyper-heuristics.html">超启发式</a> 分别展开，此处只作分类与边界的梳理，便于对号入座与放置笔记。</p><hr><h2 id="分类总览" tabindex="-1">分类总览 <a class="header-anchor" href="#分类总览" aria-label="Permalink to &quot;分类总览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>英文常称</th><th>核心特征（概括）</th></tr></thead><tbody><tr><td><a href="./simple-heuristics.html">基础启发式</a></td><td>simple / constructive / improvement heuristics 等</td><td>面向具体问题的规则或单一路径/邻域上的构造、贪心、单轮改进等，通常不以通用「搜索框架」自称</td></tr><tr><td><a href="./metaheuristics.html">元启发式</a></td><td>metaheuristics</td><td>在解空间上重复迭代的通用高层框架（如群体、热力学类比、记忆结构等），与问题建模通过编码与目标函数接口化</td></tr><tr><td><a href="./hyper-heuristics.html">超启发式</a></td><td>hyper-heuristics</td><td>在启发式算子/邻域/低层策略层面做选择、组合或生成，强调与问题解表示解耦、跨问题可迁移的管理层</td></tr></tbody></table><p>三类的边界并非绝对：元启发式里也可嵌套问题特化算子；超启发式所选对象本身常是基础启发式或小粒度元策略。写作时以「主要贡献在那一层」为准即可。</p><p>以下三节与上表一一对应，默认折叠；点击展开阅读各类定义与说明。</p><hr><details><summary>一、基础启发式 (Simple Heuristics)</summary><ul><li><strong>对象</strong>：问题结构上特化的构造规则、贪心、优先序、一阶段局部搜索等。</li><li><strong>特点</strong>：实现直接、可解释，常作为第一解、上界/可行解供精确算法热启动或剪枝使用；也可在分解法（如列生成/分支定价）中提供好的初始列或子问题解。</li><li><strong>与元启发式</strong>：不强调跨多问题的同一套迭代框架，而是「这个实例上这条规则往往好用」。</li></ul></details><details><summary>二、元启发式 (Metaheuristics)</summary><ul><li><strong>对象</strong>：在编码后的解表示上，用通用迭代机制在探索（exploration）与利用（exploitation）间平衡。</li><li><strong>代表谱系</strong>（本库会逐步展开，此处仅举例）：<a href="./simulated-annealing.html">模拟退火</a>、<a href="./tabu-search.html">禁忌搜索</a>、<a href="./genetic-algorithm.html">遗传算法</a>、<a href="./vns.html">变邻域搜索</a>、<a href="./particle-swarm-optimization.html">粒子群</a>、<a href="./ant-colony-optimization.html">蚁群</a>、<a href="./alns.html">自适应大邻域</a> 与更广进化类、差分进化等。</li><li><strong>特点</strong>：问题无关性强（同框架换编码与适应度即适用多类问题）；参数与算子对效果影响大，常与调参/自适应、混合精确子程序一起出现。</li></ul></details><details><summary>三、超启发式 (Hyper-heuristics)</summary><ul><li><strong>对象</strong>：不（主要）在全解空间上直接操作，而在低层启发式/邻域/扰动/交叉算子的池上学习或搜索：何时用哪种算子、以何顺序组合、或生成新低层规则。</li><li><strong>常见分法</strong>（文献中多交叉使用）：选择型（基于规则、强化学习、贝叶斯等，从现成算子中选序列）、生成型（以语法或学习模型生成新的启发式或邻域）等。</li><li><strong>特点</strong>：利于可迁移、可复现的「调算法」研究；在大型组合优化、调度、装箱等场景常见。</li></ul></details><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li>在 <a href="./simple-heuristics.html">基础启发式</a>、<a href="./metaheuristics.html">元启发式</a>、<a href="./hyper-heuristics.html">超启发式</a> 中逐类补充算法、伪代码、适用场景与与精确法的协作方式。</li><li>与 <a href="./exact-algorithms.html">精确算法总览</a> 对照：同一问题可写「精确分支定界 + 启发式上界/初始解」的完整工作流说明。</li></ul>',15)])])}const p=a(s,[["render",l]]);export{c as __pageData,p as default};
